const CORS_HEADERS = {
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization, X-Request-ID',
  'Access-Control-Max-Age': '86400',
};

class AppError extends Error {
  constructor(message, statusCode = 500, code = 'INTERNAL_ERROR') {
    super(message);
    this.statusCode = statusCode;
    this.code = code;
  }
}

function generateRequestId() {
  return crypto.randomUUID();
}

function sanitizeInput(input) {
  if (typeof input === 'string') {
    return input.replace(/<[^>]*>/g, '').trim().slice(0, 10000);
  }
  if (typeof input === 'object' && input !== null) {
    const sanitized = {};
    for (const [key, value] of Object.entries(input)) {
      sanitized[sanitizeInput(key)] = sanitizeInput(value);
    }
    return sanitized;
  }
  return input;
}

function validateEmail(email) {
  const emailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;
  return emailRegex.test(email) && email.length <= 254;
}

function jsonResponse(data, status = 200, extraHeaders = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      'X-Content-Type-Options': 'nosniff',
      'X-Frame-Options': 'DENY',
      'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
      'Cache-Control': 'no-store, no-cache, must-revalidate',
      'Referrer-Policy': 'strict-origin-when-cross-origin',
      ...extraHeaders,
    },
  });
}

function errorResponse(error, requestId) {
  const statusCode = error instanceof AppError ? error.statusCode : 500;
  const code = error instanceof AppError ? error.code : 'INTERNAL_ERROR';
  const message = statusCode === 500 ? 'An internal error occurred' : error.message;

  return jsonResponse(
    {
      success: false,
      error: { code, message },
      requestId,
    },
    statusCode
  );
}

async function authenticateRequest(request, env) {
  const authHeader = request.headers.get('Authorization');
  if (!authHeader) {
    throw new AppError('Missing Authorization header', 401, 'UNAUTHORIZED');
  }

  const [scheme, token] = authHeader.split(' ');
  if (scheme !== 'Bearer' || !token) {
    throw new AppError('Invalid Authorization format. Use: Bearer <token>', 401, 'UNAUTHORIZED');
  }

  const encoder = new TextEncoder();
  const tokenBytes = encoder.encode(token);
  const expectedBytes = encoder.encode(env.API_AUTH_TOKEN);

  if (tokenBytes.length !== expectedBytes.length) {
    throw new AppError('Invalid API token', 401, 'UNAUTHORIZED');
  }

  const tokenKey = await crypto.subtle.importKey(
    'raw',
    tokenBytes,
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );
  const expectedKey = await crypto.subtle.importKey(
    'raw',
    expectedBytes,
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );

  const data = encoder.encode('auth-check');
  const [sig1, sig2] = await Promise.all([
    crypto.subtle.sign('HMAC', tokenKey, data),
    crypto.subtle.sign('HMAC', expectedKey, data),
  ]);

  const match =
    new Uint8Array(sig1).every((byte, i) => byte === new Uint8Array(sig2)[i]) &&
    sig1.byteLength === sig2.byteLength;

  if (!match) {
    throw new AppError('Invalid API token', 401, 'UNAUTHORIZED');
  }

  return true;
}

async function checkRateLimit(request, env, ctx) {
  if (!env.RATE_LIMITER) {
    return;
  }

  const ip = request.headers.get('CF-Connecting-IP') || 'unknown';
  const key = `rate:${ip}`;

  const id = env.RATE_LIMITER.idFromName(key);
  const stub = env.RATE_LIMITER.get(id);
  const response = await stub.fetch(new Request('https://rate-limiter/check'));
  const result = await response.json();

  if (!result.allowed) {
    throw new AppError('Rate limit exceeded. Try again later.', 429, 'RATE_LIMITED');
  }
}

// --- SendGrid Email Service ---
class SendGridService {
  constructor(apiKey) {
    if (!apiKey) throw new AppError('SendGrid API key not configured', 500, 'CONFIG_ERROR');
    this.apiKey = apiKey;
    this.baseUrl = 'https://api.sendgrid.com/v3';
  }

  async sendEmail({ to, from, subject, textContent, htmlContent, templateId, dynamicTemplateData }) {
    if (!to || !from || !subject) {
      throw new AppError('Missing required email fields: to, from, subject', 400, 'VALIDATION_ERROR');
    }

    if (!validateEmail(to)) {
      throw new AppError('Invalid recipient email address', 400, 'VALIDATION_ERROR');
    }

    if (!validateEmail(from)) {
      throw new AppError('Invalid sender email address', 400, 'VALIDATION_ERROR');
    }

    const payload = {
      personalizations: [
        {
          to: [{ email: sanitizeInput(to) }],
          ...(dynamicTemplateData && { dynamic_template_data: sanitizeInput(dynamicTemplateData) }),
        },
      ],
      from: { email: sanitizeInput(from) },
      subject: sanitizeInput(subject),
    };

    if (templateId) {
      payload.template_id = sanitizeInput(templateId);
    } else {
      payload.content = [];
      if (textContent) {
        payload.content.push({ type: 'text/plain', value: sanitizeInput(textContent) });
      }
      if (htmlContent) {
        payload.content.push({ type: 'text/html', value: htmlContent });
      }
      if (payload.content.length === 0) {
        throw new AppError('Email must have text or HTML content', 400, 'VALIDATION_ERROR');
      }
    }

    const response = await fetch(`${this.baseUrl}/mail/send`, {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${this.apiKey}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(payload),
    });

    if (!response.ok) {
      const errorBody = await response.text();
      console.error(`SendGrid API error: ${response.status} - ${errorBody}`);

      if (response.status === 429) {
        throw new AppError('Email service rate limited. Try again later.', 429, 'SENDGRID_RATE_LIMITED');
      }
      if (response.status === 401) {
        throw new AppError('Email service authentication failed', 500, 'SENDGRID_AUTH_ERROR');
      }
      throw new AppError('Failed to send email', 502, 'SENDGRID_ERROR');
    }

    const messageId = response.headers.get('X-Message-Id');
    return { success: true, messageId };
  }
}

// --- Stripe Payment Service ---
class StripeService {
  constructor(secretKey) {
    if (!secretKey) throw new AppError('Stripe secret key not configured', 500, 'CONFIG_ERROR');
    this.secretKey = secretKey;
    this.baseUrl = 'https://api.stripe.com/v1';
  }

  async makeRequest(endpoint, method = 'GET', body = null) {
    const headers = {
      Authorization: `Bearer ${this.secretKey}`,
      'Content-Type': 'application/x-www-form-urlencoded',
      'Stripe-Version': '2023-10-16',
    };

    const options = { method, headers };

    if (body && (method === 'POST' || method === 'PUT')) {
      options.body = this.encodeFormData(body);
    }

    const response = await fetch(`${this.baseUrl}${endpoint}`, options);
    const data = await response.json();

    if (!response.ok) {
      console.error(`Stripe API error: ${response.status} - ${JSON.stringify(data)}`);

      if (response.status === 429) {
        throw new AppError('Payment service rate limited', 429, 'STRIPE_RATE_LIMITED');
      }
      if (response.status === 401) {
        throw new AppError('Payment service authentication failed', 500, 'STRIPE_AUTH_ERROR');
      }

      const stripeError = data.error || {};
      if (stripeError.type === 'card_error') {
        throw new AppError(stripeError.message || 'Card error', 400, 'CARD_ERROR');
      }
      if (stripeError.type === 'invalid_request_error') {
        throw new AppError(stripeError.message || 'Invalid request', 400, 'STRIPE_INVALID_REQUEST');
      }

      throw new AppError('Payment processing failed', 502, 'STRIPE_ERROR');
    }

    return data;
  }

  encodeFormData(obj, prefix = '') {
    const pairs = [];
    for (const [key, value] of Object.entries(obj)) {
      const fullKey = prefix ? `${prefix}[${key}]` : key;
      if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
        pairs.push(this.encodeFormData(value, fullKey));
      } else if (Array.isArray(value)) {
        value.forEach((item, index) => {
          pairs.push(`${encodeURIComponent(`${fullKey}[${index}`)}]=${encodeURIComponent(item)}`);
        });
      } else {
        pairs.push(`${encodeURIComponent(fullKey)}=${encodeURIComponent(value)}`);
      }
    }
    return pairs.join('&');
  }

  async createPaymentIntent({ amount, currency = 'usd', customerId, metadata, description }) {
    if (!amount || typeof amount !== 'number' || amount < 50) {
      throw new AppError('Amount must be a number >= 50 (in cents)', 400, 'VALIDATION_ERROR');
    }

    const allowedCurrencies = ['usd', 'eur', 'gbp', 'cad', 'aud', 'jpy'];
    if (!allowedCurrencies.includes(currency.toLowerCase())) {
      throw new AppError(`Currency must be one of: ${allowedCurrencies.join(', ')}`, 400, 'VALIDATION_ERROR');
    }

    const body = {
      amount: Math.round(amount),
      currency: currency.toLowerCase(),
      automatic_payment_methods: { enabled: 'true' },
    };

    if (customerId) body.customer = sanitizeInput(customerId);
    if (description) body.description = sanitizeInput(description).slice(0, 500);
    if (metadata) {
      const sanitizedMeta = sanitizeInput(metadata);
      body.metadata = {};
      for (const [k, v] of Object.entries(sanitizedMeta)) {
        body.metadata[k.slice(0, 40)] = String(v).slice(0, 500);
      }
    }

    return this.makeRequest('/payment_intents', 'POST', body);
  }

  async retrievePaymentIntent(paymentIntentId) {
    if (!paymentIntentId || !paymentIntentId.startsWith('pi_')) {
      throw new AppError('Invalid payment intent ID', 400, 'VALIDATION_ERROR');
    }
    return this.makeRequest(`/payment_intents/${encodeURIComponent(paymentIntentId)}`);
  }

  async createCustomer({ email, name, metadata }) {
    if (!email || !validateEmail(email)) {
      throw new AppError('Valid email is required to create a customer', 400, 'VALIDATION_ERROR');
    }

    const body = { email: sanitizeInput(email) };
    if (name) body.name = sanitizeInput(name).slice(0, 256);
    if (metadata) body.metadata = sanitizeInput(metadata);

    return this.makeRequest('/customers', 'POST', body);
  }

  async createRefund({ paymentIntentId, amount, reason }) {
    if (!paymentIntentId || !paymentIntentId.startsWith('pi_')) {
      throw new AppError('Invalid payment intent ID for refund', 400, 'VALIDATION_ERROR');
    }

    const body = { payment_intent: paymentIntentId };
    if (amount) body.amount = Math.round(amount);
    if (reason) {
      const validReasons = ['duplicate', 'fraudulent', 'requested_by_customer'];
      if (!validReasons.includes(reason)) {
        throw new AppError(`Refund reason must be one of: ${validReasons.join(', ')}`, 400, 'VALIDATION_ERROR');
      }
      body.reason = reason;
    }

    return this.makeRequest('/refunds', 'POST', body);
  }

  async verifyWebhookSignature(payload, signatureHeader, webhookSecret) {
    if (!signatureHeader || !webhookSecret) {
      throw new AppError('Missing webhook signature or secret', 400, 'WEBHOOK_ERROR');
    }

    const elements = signatureHeader.split(',');
    const signatures = {};
    for (const element of elements) {
      const [key, value] = element.split('=');
      if (!signatures[key]) signatures[key] = [];
      signatures[key].push(value);
    }

    const timestamp = signatures['t'] && signatures['t'][0];
    const v1Signatures = signatures['v1'] || [];

    if (!timestamp || v1Signatures.length === 0) {
      throw new AppError('Invalid webhook signature format', 400, 'WEBHOOK_ERROR');
    }

    // Reject timestamps older than 5 minutes
    const currentTime = Math.floor(Date.now() / 1000);
    if (Math.abs(currentTime - parseInt(timestamp)) > 300) {
      throw new AppError('Webhook timestamp too old', 400, 'WEBHOOK_EXPIRED');
    }

    const signedPayload = `${timestamp}.${payload}`;
    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(webhookSecret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['sign']
    );

    const signatureBuffer = await crypto.subtle.sign('HMAC', key, encoder.encode(signedPayload));
    const expectedSignature = Array.from(new Uint8Array(signatureBuffer))
      .map((b) => b.toString(16).padStart(2, '0'))
      .join('');

    const isValid = v1Signatures.some((sig) => {
      if (sig.length !== expectedSignature.length) return false;
      let result = 0;
      for (let i = 0; i < sig.length; i++) {
        result |= sig.charCodeAt(i) ^ expectedSignature.charCodeAt(i);
      }
      return result === 0;
    });

    if (!isValid) {
      throw new AppError('Invalid webhook signature', 400, 'WEBHOOK_INVALID_SIGNATURE');
    }

    return true;
  }
}

// --- Route Handlers ---

async function handleSendEmail(request, env) {
  const body = await request.json();
  const sendgrid = new SendGridService(env.SENDGRID_API_KEY);

  const result = await sendgrid.sendEmail({
    to: body.to,
    from: body.from || env.DEFAULT_FROM_EMAIL || 'noreply@yourdomain.com',
    subject: body.subject,
    textContent: body.textContent,
    htmlContent: body.htmlContent,
    templateId: body.templateId,
    dynamicTemplateData: body.dynamicTemplateData,
  });

  return jsonResponse({ success: true, data: result });
}

async function handleCreatePaymentIntent(request, env) {
  const body = await request.json();
  const stripe = new StripeService(env.STRIPE_SECRET_KEY);

  const paymentIntent = await stripe.createPaymentIntent({
    amount: body.amount,
    currency: body.currency,
    customerId: body.customerId,
    metadata: body.metadata,
    description: body.description,
  });

  return jsonResponse({
    success: true,
    data: {
      id: paymentIntent.id,
      clientSecret: paymentIntent.client_secret,
      amount: paymentIntent.amount,
      currency: paymentIntent.currency,
      status: paymentIntent.status,
    },
  });
}

async function handleGetPaymentIntent(request, env) {
  const url = new URL(request.url);
  const id = url.pathname.split('/').pop();
  const stripe = new StripeService(env.STRIPE_SECRET_KEY);

  const paymentIntent = await stripe.retrievePaymentIntent(id);

  return jsonResponse({
    success: true,
    data: {
      id: paymentIntent.id,
      amount: paymentIntent.amount,
      currency: paymentIntent.currency,
      status: paymentIntent.status,
      created: paymentIntent.created,
    },
  });
}

async function handleCreateCustomer(request, env) {
  const body = await request.json();
  const stripe = new StripeService(env.STRIPE_SECRET_KEY);

  const customer = await stripe.createCustomer({
    email: body.email,
    name: body.name,
    metadata: body.metadata,
  });

  return jsonResponse({
    success: true,
    data: {
      id: customer.id,
      email: customer.email,
      name: customer.name,
    },
  });
}

async function handleCreateRefund(request, env) {
  const body = await request.json();
  const stripe = new StripeService(env.STRIPE_SECRET_KEY);

  const refund = await stripe.createRefund({
    paymentIntentId: body.paymentIntentId,
    amount: body.amount,
    reason: body.reason,
  });

  return jsonResponse({
    success: true,
    data: {
      id: refund.id,
      amount: refund.amount,
      status: refund.status,
      paymentIntent: refund.payment_intent,
    },
  });
}

async function handleStripeWebhook(request, env) {
  const stripe = new StripeService(env.STRIPE_SECRET_KEY);
  const payload = await request.text();
  const signatureHeader = request.headers.get('Stripe-Signature');

  await stripe.verifyWebhookSignature(payload, signatureHeader, env.WEBHOOK_SIGNING_SECRET);

  const event = JSON.parse(payload);

  console.log(`Stripe webhook received: ${event.type} - ${event.id}`);

  switch (event.type) {
    case 'payment_intent.succeeded': {
      const paymentIntent = event.data.object;
      console.log(`Payment succeeded: ${paymentIntent.id} - ${paymentIntent.amount} ${paymentIntent.currency}`);

      // Optionally send confirmation email
      if (paymentIntent.receipt_email || paymentIntent.metadata?.email) {
        try {
          const sendgrid = new SendGridService(env.SENDGRID_API_KEY);
          await sendgrid.sendEmail({
            to: paymentIntent.receipt_email || paymentIntent.metadata.email,
            from: env.DEFAULT_FROM_EMAIL || 'noreply@yourdomain.com',
            subject: 'Payment Confirmation',
            textContent: `Your payment of ${(paymentIntent.amount / 100).toFixed(2)} ${paymentIntent.currency.toUpperCase()} has been received. Payment ID: ${paymentIntent.id}`,
          });
        } catch (emailError) {
          console.error(`Failed to send confirmation email: ${emailError.message}`);
        }
      }
      break;
    }

    case 'payment_intent.payment_failed': {
      const failedPayment = event.data.object;
      console.error(`Payment failed: ${failedPayment.id} - ${failedPayment.last_payment_error?.message}`);
      break;
    }

    case 'charge.refunded': {
      const charge = event.data.object;
      console.log(`Charge refunded: ${charge.id}`);
      break;
    }

    case 'customer.created': {
      const customer = event.data.object;
      console.log(`Customer created: ${customer.id} - ${customer.email}`);
      break;
    }

    default:
      console.log(`Unhandled webhook event type: ${event.type}`);
  }

  return jsonResponse({ received: true });
}

