// --- Router ---

class Router {
  constructor() {
    this.routes = [];
  }

  add(method, pattern, handler, options = {}) {
    const regex = new RegExp(
      '^' + pattern.replace(/:[a-zA-Z]+/g, '([^/]+)') + '$'
    );
    this.routes.push({ method, pattern, regex, handler, ...options });
  }

  match(method, pathname) {
    for (const route of this.routes) {
      if (route.method === method || route.method === 'ALL') {
        const match = pathname.match(route.regex);
        if (match) {
          return { route, params: match.slice(1) };
        }
      }
    }
    return null;
  }
}

const router = new Router();

// Public routes (no auth required)
router.add('GET', '/health', handleHealthCheck, { public: true });
router.add('POST', '/webhooks/stripe', handleStripeWebhook, { public: true });

// Authenticated routes
router.add('POST', '/api/email/send', handleSendEmail);
router.add('POST', '/api/payments/intents', handleCreatePaymentIntent);
router.add('GET', '/api/payments/intents/:id', handleGetPaymentIntent);
router.add('POST', '/api/customers', handleCreateCustomer);
router.add('POST', '/api/refunds', handleCreateRefund);

// --- Main Worker Export ---

export default {
  async fetch(request, env, ctx) {
    const requestId = request.headers.get('X-Request-ID') || generateRequestId();
    const startTime = Date.now();

    try {
      // CORS preflight
      if (request.method === 'OPTIONS') {
        const allowedOrigin = env.ALLOWED_ORIGINS || '*';
        return new Response(null, {
          status: 204,
          headers: {
            ...CORS_HEADERS,
            'Access-Control-Allow-Origin': allowedOrigin,
          },
        });
      }

      const url = new URL(request.url);
      const pathname = url.pathname;

      // Route matching
      const matched = router.match(request.method, pathname);

      if (!matched) {
        throw new AppError('Not Found', 404, 'NOT_FOUND');
      }

      const { route } = matched;

      // Authentication for non-public routes
      if (!route.public) {
        await authenticateRequest(request, env);
      }

      // Rate limiting
      await checkRateLimit(request, env, ctx);

      // Request size limit (1MB)
      const contentLength = request.headers.get('Content-Length');
      if (contentLength && parseInt(contentLength) > 1048576) {
        throw new AppError('Request body too large', 413, 'PAYLOAD_TOO_LARGE');
      }

      // Content-Type validation for POST/PUT
      if (['POST', 'PUT', 'PATCH'].includes(request.method) && !route.public) {
        const contentType = request.headers.get('Content-Type');
        if (!contentType || !contentType.includes('application/json')) {
          throw new AppError('Content-Type must be application/json', 415, 'UNSUPPORTED_MEDIA_TYPE');
        }
      }

      // Execute handler
      const response = await route.handler(request, env, ctx);

      // Add common headers
      const allowedOrigin = env.ALLOWED_ORIGINS || '*';
      response.headers.set('Access-Control-Allow-Origin', allowedOrigin);
      response.headers.set('X-Request-ID', requestId);
      response.headers.set('X-Response-Time', `${Date.now() - startTime}ms`);

      // Log request
      console.log(
        JSON.stringify({
          requestId,
          method: request.method,
          path: pathname,
          status: response.status,
          duration: Date.now() - startTime,
          ip: request.headers.get('CF-Connecting-IP'),
          country: request.headers.get('CF-IPCountry'),
          userAgent: request.headers.get('User-Agent')?.slice(0, 200),
        })
      );

      return response;
    } catch (error) {
      // Log error
      console.error(
        JSON.stringify({
          requestId,
          error: error.message,
          code: error.code || 'UNKNOWN',
          stack: error.stack?.slice(0, 500),
          method: request.method,
          path: new URL(request.url).pathname,
          duration: Date.now() - startTime,
        })
      );

      const response = errorResponse(error, requestId);
      const allowedOrigin = env.ALLOWED_ORIGINS || '*';
      response.headers.set('Access-Control-Allow-Origin', allowedOrigin);
      response.headers.set('X-Request-ID', requestId);
      return response;
    }
  },
};

// --- Optional: Rate Limiter Durable Object ---
// Uncomment and add to wrangler.toml if you want built-in rate limiting:
// [durable_objects]
// bindings = [{ name = "RATE_LIMITER", class_name = "RateLimiter" }]

export class RateLimiter {
  constructor(state, env) {
    this.state = state;
    this.env = env;
  }

  async fetch(request) {
    const now = Date.now();
    const windowMs = 60000; // 1 minute window
    const maxRequests = 60; // 60 requests per minute

    let data = (await this.state.storage.get('rateData')) || { requests: [], blocked_until: 0 };

    // Check if currently blocked
    if (data.blocked_until > now) {
      return new Response(
        JSON.stringify({ allowed: false, retryAfter: Math.ceil((data.blocked_until - now) / 1000) }),
        { headers: { 'Content-Type': 'application/json' } }
      );
    }

    // Clean old requests
    data.requests = data.requests.filter((ts) => ts > now - windowMs);

    if (data.requests.length >= maxRequests) {
      data.blocked_until = now + 60000; // Block for 1 minute
      await this.state.storage.put('rateData', data);
      return new Response(
        JSON.stringify({ allowed: false, retryAfter: 60 }),
        { headers: { 'Content-Type': 'application/json' } }
      );
    }

    data.requests.push(now);
    await this.state.storage.put('rateData', data);

    return new Response(
      JSON.stringify({ allowed: true, remaining: maxRequests - data.requests.length }),
      { headers: { 'Content-Type': 'application/json' } }
    );
  }
}